import{_ as e,o as l,c as r,ai as t}from"./chunks/framework.CaiDwmc7.js";const u=JSON.parse('{"title":"常用 Linux 命令与线上排查实战","description":"","frontmatter":{},"headers":[],"relativePath":"network-linux/linux-cmd.md","filePath":"network-linux/linux-cmd.md"}'),n={name:"network-linux/linux-cmd.md"};function d(c,o,i,s,a,g){return l(),r("div",null,[...o[0]||(o[0]=[t('<h1 id="常用-linux-命令与线上排查实战" tabindex="-1">常用 Linux 命令与线上排查实战 <a class="header-anchor" href="#常用-linux-命令与线上排查实战" aria-label="Permalink to “常用 Linux 命令与线上排查实战”">​</a></h1><hr><h3 id="❓-面试官-日常开发和线上排查-你最常用哪些-linux-命令" tabindex="-1">❓ 面试官：日常开发和线上排查，你最常用哪些 Linux 命令？ <a class="header-anchor" href="#❓-面试官-日常开发和线上排查-你最常用哪些-linux-命令" aria-label="Permalink to “❓ 面试官：日常开发和线上排查，你最常用哪些 Linux 命令？”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 面试回答这个问题，不要干巴巴地背 <code>ls、cd、pwd</code>。一定要<strong>结合具体的后端工作场景分类来答</strong>，体现你不仅懂命令，还懂排查思路。</p><p><strong>📝 场景化高分回答剧本：</strong></p><p>&quot;我平时主要在以下三个场景使用 Linux 命令：&quot;</p><p><strong>场景一：排查日志与搜索文件（最常用）</strong></p><ul><li><strong><code>tail -f xxx.log</code></strong>：看最新的实时滚动日志。通常配合 <code>grep</code>，比如 <code>tail -f info.log | grep &#39;NullPointer&#39;</code> 只看报错的日志。</li><li><strong><code>less xxx.log</code></strong>：看大日志文件。用 <code>/</code> 搜索关键字，<code>N</code> 找下一个，不占用内存，比 <code>cat</code> 安全。</li><li><strong><code>grep -n &#39;订单号&#39; xxx.log</code></strong>：全量搜寻某个订单的出错记录，并显示行号。</li><li><strong><code>find / -name &quot;*.jar&quot;</code></strong>：全盘搜索不知道放哪里的 jar 包或者配置文件。</li></ul><p><strong>场景二：查看网络连接与端口号占用</strong></p><ul><li><strong><code>netstat -nltp | grep 8080</code></strong>：起项目报错端口被占用时，用这个查谁占了 8080 端口，拿到 PID 后用 <code>kill -9</code> 杀掉。</li><li><strong><code>ping</code> 和 <code>telnet ip port</code></strong>：如果是分布式服务调不通，先 <code>ping</code> 看网络通不通，再 <code>telnet</code> 看对方防火墙有没有开这个端口。</li></ul><p><strong>场景三：排查服务器性能（CPU/内存/磁盘）</strong></p><ul><li><strong><code>top</code></strong>：查看整个系统的 CPU 和内存使用率，类似 Windows 的任务管理器。</li><li><strong><code>free -h</code></strong>：直观查看系统的可用内存（带单位 G/M）。</li><li><strong><code>df -h</code></strong>：看磁盘有没有被打满，如果是 <code>100%</code>，会导致 MySQL 挂掉或者日志写不进去。</li></ul><hr><h3 id="❓-面试官-如果线上系统突然变得非常卡-你怎么排查-线上-cpu-飙高排查流程-【中级】" tabindex="-1">❓ 面试官：如果线上系统突然变得非常卡，你怎么排查？（线上 CPU 飙高排查流程）【中级】 <a class="header-anchor" href="#❓-面试官-如果线上系统突然变得非常卡-你怎么排查-线上-cpu-飙高排查流程-【中级】" aria-label="Permalink to “❓ 面试官：如果线上系统突然变得非常卡，你怎么排查？（线上 CPU 飙高排查流程）【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 排查思路是：<strong>定位高负载进程 -&gt; 定位高负载线程 -&gt; 线程 ID 转十六进制 -&gt; 通过 jstack 找出正在执行的代码行数</strong>。</p><p><strong>📝 详细的四步排查大法（背熟这个流程）：</strong></p><ol><li><strong>第一步：找元凶进程（PID）</strong><ul><li>敲 <code>top</code> 命令，看第一行的数据。如果 <code>load average</code>（系统负载）很高，且找到了占据 CPU 90% 以上的 Java 进程。记下它的进程 ID（比如是 <code>1001</code>）。</li></ul></li><li><strong>第二步：找元凶线程（TID）</strong><ul><li>敲 <code>top -Hp 1001</code>。这会显示进程 <code>1001</code> 下面的所有线程。找到消耗 CPU 最高的那一个线程，记下它的线程 ID（比如是 <code>1010</code>）。</li></ul></li><li><strong>第三步：将 TID 转成十六进制</strong><ul><li>因为 JVM 的堆栈信息里，线程 ID 是用十六进制表示的。用命令 <code>printf &quot;%x\\n&quot; 1010</code> 把它转成十六进制，比如得到 <code>3f2</code>。</li></ul></li><li><strong>第四步：通过 jstack 定位死循环代码</strong><ul><li>敲 <code>jstack 1001 | grep -A 20 &#39;3f2&#39;</code>（把进程栈导出来，并在里面搜这个十六进制的线程 ID，显示前后 20 行）。</li><li><strong>结果：</strong>这时候控制台上就会清晰地打印出这个疯狂占用 CPU 的线程<strong>正在执行哪个类的哪一行代码</strong>。通常会发现是一个业务代码写了死循环，或者一直在做极耗 CPU 的正则匹配/大量对象计算。赶紧下线机器去改代码！</li></ul></li></ol><hr><h3 id="❓-面试官-线上系统报错-oom-内存溢出-你是怎么排查的-【中级】" tabindex="-1">❓ 面试官：线上系统报错 OOM（内存溢出），你是怎么排查的？【中级】 <a class="header-anchor" href="#❓-面试官-线上系统报错-oom-内存溢出-你是怎么排查的-【中级】" aria-label="Permalink to “❓ 面试官：线上系统报错 OOM（内存溢出），你是怎么排查的？【中级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> OOM 发生时不能靠猜。核心手段是<strong>获取系统崩溃瞬间的 Heap Dump（堆内存快照）文件</strong>，然后用可视化工具（如 MAT 或 JVisualVM）分析是哪个大对象把内存撑爆了。</p><p><strong>📝 详细排查实战：</strong></p><ol><li><strong>事前防御：开启自动 Dump</strong><ul><li>在 Java 项目启动参数中，我一定会加上： <code>-XX:+HeapDumpOnOutOfMemoryError</code>（发生 OOM 时自动生成 dump 文件） <code>-XX:HeapDumpPath=/log/heapdump.hprof</code>（指定生成路径）。</li><li>否则 OOM 时进程直接退出，神仙也查不出当时内存里有啥。</li></ul></li><li><strong>事发取证</strong><ul><li>发生 OOM 报警后，去服务器上的 <code>/log/</code> 目录把那个 <code>.hprof</code> 快照文件下载到本地电脑。</li></ul></li><li><strong>事后分析</strong><ul><li>用 Eclipse MAT（Memory Analyzer Tool）打开快照文件。</li><li>看它的 <strong>&quot;Leak Suspects&quot;（泄漏嫌疑人）</strong> 报告。它会直接用大饼图告诉你：“有 90% 的内存都被一个叫 <code>ArrayList</code> 的对象占据，里面塞满了 <code>UserEntity</code> 对象”。</li><li>顺藤摸瓜点进去，能看到这些对象的创建引用链，最后定位到：原来是一段老代码在执行 <code>select * from user</code> 忘了加分页条件，一下子把数据库里 200 万用户全查到内存里，导致了 OOM。</li></ul></li><li><strong>修复与总结</strong><ul><li>加上分页查询逻辑，发布上线。</li></ul></li></ol><hr><h3 id="❓-面试官-说一下-chmod-命令的作用-chmod-777-代表什么意思" tabindex="-1">❓ 面试官：说一下 chmod 命令的作用？<code>chmod 777</code> 代表什么意思？ <a class="header-anchor" href="#❓-面试官-说一下-chmod-命令的作用-chmod-777-代表什么意思" aria-label="Permalink to “❓ 面试官：说一下 chmod 命令的作用？chmod 777 代表什么意思？”">​</a></h3><p><em>频率：🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong><code>chmod</code> 用来修改文件或目录的<strong>读（r）、写（w）、执行（x）权限</strong>。</p><p><strong>📝 详细解释：</strong></p><ul><li>Linux 中，权限分为三组：<strong>所有者（User）</strong>、<strong>同组用户（Group）</strong>、<strong>其他用户（Other）</strong>。</li><li>权限的分值：读 <code>r = 4</code>，写 <code>w = 2</code>，执行 <code>x = 1</code>。没有权限就是 <code>0</code>。</li><li><strong><code>777</code> 解析</strong>： <ul><li>第一个 7（4+2+1）：文件所有者拥有读、写、执行的全部权限。</li><li>第二个 7：同组用户拥有读、写、执行的全部权限。</li><li>第三个 7：其他任意用户拥有读、写、执行的全部权限。</li></ul></li><li><strong>实战注意</strong>：在生产环境中，千万不要乱用 <code>chmod 777</code>（谁都能改谁都能删，极度危险）。一般给个 <code>chmod 755</code>（自己可写，别人只能读和执行）或者用作临时调试，调试完立马改回去。</li></ul>',31)])])}const h=e(n,[["render",d]]);export{u as __pageData,h as default};
